import java.util.ArrayList;
import java.util.Collections;
import java.util.Comparator;
import java.util.List;
import java.util.regex.Pattern;

public static String[] solve(String[] code, String[] businessLine, boolean[] isActive) {
    List<String[]> validCoupons = new ArrayList<>();
    Pattern pattern = Pattern.compile("^[a-zA-Z0-9_]+$");

    for (int i = 0; i < code.length; i++) {
        String currentCode = code[i];
        String currentBusiness = businessLine[i];
        boolean currentActive = isActive[i];

        if (currentCode == null || currentCode.isEmpty()) {
            continue;
        }
        if (!pattern.matcher(currentCode).matches()) {
            continue;
        }
        if (!isValidBusinessLine(currentBusiness)) {
            continue;
        }
        if (!currentActive) {
            continue;
        }

        validCoupons.add(new String[]{currentBusiness, currentCode});
    }

    Collections.sort(validCoupons, new Comparator<String[]>() {
        @Override
        public int compare(String[] a, String[] b) {
            int orderA = getBusinessLineOrder(a[0]);
            int orderB = getBusinessLineOrder(b[0]);
            if (orderA != orderB) {
                return Integer.compare(orderA, orderB);
            } else {
                return a[1].compareTo(b[1]);
            }
        }
    });

    String[] result = new String[validCoupons.size()];
    for (int i = 0; i < validCoupons.size(); i++) {
        result[i] = validCoupons.get(i)[1];
    }
    return result;
}

private static boolean isValidBusinessLine(String businessLine) {
    return businessLine.equals("electronics") || businessLine.equals("grocery") 
        || businessLine.equals("pharmacy") || businessLine.equals("restaurant");
}

private static int getBusinessLineOrder(String businessLine) {
    switch (businessLine) {
        case "electronics": return 0;
        case "grocery": return 1;
        case "pharmacy": return 2;
        case "restaurant": return 3;
        default: return -1;
    }
}
